    public function logout()
    {
        try {
            Auth::logout();
            toastify()->success('Anda telah berhasil keluar');
            return redirect(route('login.index'));
        } catch (\Exception $e) {
            toastify()->error('Terjadi kesalahan saat logout: ' . $e->getMessage());
            return redirect()->back();
        }
    }

